"""
MKT Christ-in-Every-Verse Commentary — Genesis chapter 24
Run: python3 scripts/zc-christ-genesis-24-24.py

Source data used:
- data/interlinear/genesis.json
- data/translation/draft/mediating/genesis.json (MKT text)
- data/commentary/mkt-christ/genesis.json (existing: chs 1–23 complete)

Key typological decisions:
- Genesis 24 carries one of the richest sustained typologies in the OT: Abraham
  (God the Father) sends his unnamed servant (the Holy Spirit) to secure a bride
  (Rebekah/the Church) for his son Isaac (Christ). This typological reading has
  a long history in Christian exegesis (Origen, Augustine, Calvin) and is
  grounded in NT marriage-and-bride theology: Eph 5:25-32 (marriage = mystery
  pointing to Christ and church), 2 Cor 11:2 (Paul presents the church as a
  pure virgin to Christ), Rev 19:7-9 (marriage supper of the Lamb), Rev 22:17
  (Spirit and bride say "Come"), John 15:26; 16:13-14 (Spirit testifies of
  Christ, glorifies Christ, does not speak on his own).
- The servant's name is never given — a detail that reinforces the type: the
  Spirit does not draw attention to himself but always points to the Son
  (John 16:14: "He will glorify me").
- The servant's refusal to eat until his mission message is delivered (v33) is
  explicitly paralleled with Jesus in John 4:34 ("My food is to do the will of
  him who sent me").
- Rebekah's "I will go" (v58) is treated as the paradigm of free faith-response
  to the Spirit's gospel call — the bride must choose freely.
- The gifts (vv22, 53) are treated as types of the Spirit's gifts (Eph 1:13-14;
  1 Cor 12:4-11), specifically the Spirit as "deposit guaranteeing our
  inheritance" (Eph 1:14).
- Beer Lahai Roi (v62) — where Hagar met "the God who sees" (16:14) — is noted
  as the place Isaac dwells: grace reaching the outcast.
- "He loved her" (v67) connects to Eph 5:25; "comforted after his mother's
  death" connects to John 16:22.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-christ commentary for Genesis 24 — the sending of the servant
#   to find a bride for Isaac. The chapter bears a sustained typology (Father/
#   Spirit/Son/Church) that runs from the mission-oath (vv1-9) through the
#   servant's proclamation (vv34-49) to the wedding (v67).
# CHANGE? If data/commentary/mkt-christ/genesis.json structure changes, update
#   load_comm/save_comm in Z_COMMENTARY_SCRIPT_GUIDE.md accordingly.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-christ/genesis.json')); print(len(d.get('24',{})))" should print "67".

NEW_DATA = {
"24": {
"1": "<p>&#8220;Abraham was now very old, and the LORD had blessed him in every way.&#8221; The completed life of the covenant father frames the next act of the covenant drama: securing the continuation of the promise through the son. The fullness of blessing that rests on Abraham is the context for his son&#8217;s inheritance. Heb 1:2 &#8212; God has &#8220;appointed [Christ] heir of all things&#8221; &#8212; is the NT form of the same logic: the Father&#8217;s blessing is complete; now the concern is the Son&#8217;s bride and inheritance. The chapter that begins with Abraham&#8217;s comprehensive blessing ends with Isaac&#8217;s marriage &#8212; the covenant moving from father to son through the mission of the servant.</p>",
"2": "<p>The senior servant of Abraham&#8217;s household &#8212; the one in charge of all he had &#8212; is never named in ch24, a detail that has long attracted theological attention. The servant&#8217;s namelessness is consistent with the typological reading of the Spirit: &#8220;he will not speak on his own; he will speak only what he hears&#8230; He will glorify me&#8221; (John 16:13&#8211;14). The Spirit does not draw attention to himself but always directs to the Son. The oath sworn &#8220;under the thigh&#8221; &#8212; invoking the covenant of circumcision (cf. 47:29) &#8212; is the most solemn form of commitment available; the servant binds himself to the mission of the son&#8217;s bride by the covenant&#8217;s own sign.</p>",
"3": "<p>&#8220;Not from the daughters of the Canaanites&#8221; &#8212; the bride for the covenant son must not come from the surrounding pagan world. The church is defined by &#8220;called out&#8221; (<em>ekklēsia</em>) &#8212; gathered from the world but not formed by the world&#8217;s pattern. John 17:14&#8211;16 &#8212; &#8220;they are not of the world, even as I am not of it&#8221; &#8212; is Christ&#8217;s prayer for the church that corresponds to Abraham&#8217;s instruction: the bride for the Son must not be sourced from the Canaanite world. The purity of origin is not ethnic but covenantal &#8212; the bride must come from those who know the God of Abraham.</p>",
"4": "<p>&#8220;But will go to my country and my own relatives.&#8221; The bride comes from within the extended covenant family &#8212; from Ur-kindred who share the same father Terah (11:27&#8211;31). Spiritually, the church is gathered from among those who have the covenant heritage &#8212; first to the Jew, then to the Gentile (Rom 1:16), always from among those to whom the promise has been sent. The principle is that the bride is sought among those who already stand within the circle of divine revelation, however partially known. Paul&#8217;s mission strategy (Acts 17:2 &#8212; beginning in the synagogue) reflects the same logic.</p>",
"5": "<p>&#8220;What if the woman is unwilling to come back with me?&#8221; The servant&#8217;s practical question anticipates the freedom of the bride&#8217;s response. The gospel is not coercion; the Spirit does not force. The Rebekah of v58 must say &#8220;I will go&#8221; of her own will. This freedom of response is the freedom of faith: &#8220;all those the Father gives me will come to me&#8221; (John 6:37), yet the coming is genuinely chosen. The servant&#8217;s question honors the bride&#8217;s freedom; the Father&#8217;s plan makes room for a freely given &#8220;yes.&#8221;</p>",
"6": "<p>&#8220;Make sure that you do not take my son back there.&#8221; Isaac must remain in the land of promise &#8212; the servant&#8217;s mission is to bring the bride to the son, not to return the son to where the bride is. Christ does not return to the state of humiliation; the Spirit&#8217;s mission is to draw the bride to Christ (John 6:44 &#8212; &#8220;No one can come to me unless the Father who sent me draws them&#8221;), not to bring Christ back into the world&#8217;s condition. The bride must leave her old home; the bridegroom stays in his place of glory and awaits her coming (John 14:3 &#8212; &#8220;I will come back and take you to be with me&#8221;).</p>",
"7": "<p>&#8220;He will send his angel before you.&#8221; The divine promise of angelic guidance for the servant&#8217;s mission. The Spirit does not work alone; the Father sends divine provision ahead of the Spirit&#8217;s mission. The same language of divine accompaniment and preceding guidance marks the Spirit&#8217;s work in Acts: 16:6&#8211;10 (the Spirit prevents, opens, redirects); 8:26 (an angel directs Philip to the Ethiopian). The servant goes with the promise that the LORD has already gone ahead &#8212; the Spirit is the advance team of a mission that the Father has already ordained and for which he has already prepared the one who will respond.</p>",
"8": "<p>&#8220;If the woman is unwilling to come back with you, you will be released from this oath.&#8221; The Spirit&#8217;s mission can be refused. The woman who refuses releases the servant from his obligation &#8212; the Spirit will not force the response of faith. This is the structure of gospel proclamation: the Spirit presents the invitation, but those who refuse are not compelled. John 16:8&#8211;11 &#8212; the Spirit convicts of sin, righteousness, and judgment &#8212; describes the Spirit&#8217;s persuasive work, not an irresistible override. The freedom to refuse is real; the servant&#8217;s commission is fulfilled in the proclamation, not in the coercion.</p>",
"9": "<p>The servant swears the oath &#8212; full commitment to the mission of securing the son&#8217;s bride. The Spirit&#8217;s faithfulness to his mission of testifying of Christ is described in John 15:26: &#8220;When the Advocate comes, whom I will send to you from the Father &#8212; the Spirit of truth who goes out from the Father &#8212; he will testify about me.&#8221; The servant&#8217;s sworn commitment under the covenant sign is the type of the Spirit&#8217;s eternal commitment to the mission of bringing people to Christ &#8212; a mission that does not waver because the Spirit proceeds from both the Father who sends and the Son on whose behalf he works.</p>",
"10": "<p>Ten camels loaded with &#8220;all kinds of good things from his master.&#8221; The gifts that accompany the servant&#8217;s mission come from the master&#8217;s own household &#8212; they are not the servant&#8217;s own resources. The Spirit gives &#8220;all kinds of good things&#8221; from the Father&#8217;s household to the bride: 1 Cor 12:4&#8211;11 (spiritual gifts distributed by the Spirit as he determines); Eph 1:13&#8211;14 (the Spirit himself as the seal and guarantee of the inheritance). The ten camels may echo the covenant completeness of the number ten (the ten commandments as the covenant charter; the ten plagues as covenant judgment). The gifts of grace accompany every genuine gospel mission.</p>",
"11": "<p>The camels kneel at the well outside the town, at evening &#8212; when the women come out to draw water. The well is the meeting point of life and necessity &#8212; the place of ordinary daily need. The Spirit meets people at the point of their ordinary life, not in extraordinary settings. John 4:6&#8211;14 &#8212; Jesus meets the Samaritan woman at a well, at midday &#8212; is the NT parallel: the encounter that leads to living water begins at the place of ordinary thirst. The servant&#8217;s positioning &#8220;near the well&#8221; is the Spirit&#8217;s presence at the point of human need and longing.</p>",
"12": "<p>&#8220;LORD, God of my master Abraham, make me successful today, and show kindness to my master Abraham.&#8221; The servant&#8217;s prayer before the encounter is the model of Spirit-led intercession: grounded in divine covenant love (<em>ḥesed</em>, translated &#8220;kindness&#8221;), oriented toward the master&#8217;s purposes, and dependent entirely on divine initiative rather than the servant&#8217;s own skill. Rom 8:26&#8211;27 &#8212; &#8220;the Spirit himself intercedes for us with groans that words cannot express&#8230; intercedes for God&#8217;s people in accordance with the will of God&#8221; &#8212; is the NT form of the same structure: the Spirit&#8217;s intercessory faithfulness undergirds the mission of bringing people to Christ.</p>",
"13": "<p>&#8220;See, I am standing beside this spring.&#8221; The servant places himself precisely at the point of daily need and announces the meeting before it happens. This is the pattern of the Spirit&#8217;s gospel work: he positions the church at the points of human need (physical, social, spiritual) where encounters occur. Acts 3:1&#8211;10 (Peter and John at the temple gate at the hour of prayer, the daily meeting point of need and divine encounter) follows the same pattern. The servant&#8217;s &#8220;see, I am standing&#8221; is the Spirit&#8217;s presence at the ordinary intersection of life.</p>",
"14": "<p>The sign of the bride: the woman who offers to water the camels as well as the man. Ten camels, each capable of drinking 25 gallons after a long journey &#8212; potentially 250 gallons drawn by hand from a well. The extravagant generosity beyond the minimum required is the character trait of the appointed bride. This is the love that &#8220;does not seek its own&#8221; (1 Cor 13:5), the service-ethic of the new covenant community: &#8220;let each of you look not to your own interests, but to the interests of others&#8221; (Phil 2:4). The servant&#8217;s sign-request defines the church by her character of generous, self-giving service &#8212; not by her beauty alone (though Rebekah is beautiful, v16).</p>",
"15": "<p>&#8220;Before he had finished praying, Rebekah came out.&#8221; Divine provision anticipates the completion of prayer. Isa 65:24 &#8212; &#8220;before they call I will answer; while they are yet speaking I will hear.&#8221; The Spirit&#8217;s mission is not dependent on the completion of the servant&#8217;s request &#8212; God had already prepared Rebekah, already positioned her at the well, already appointed the encounter. The prevenient grace that brings Rebekah out before the prayer is finished is the same grace that Paul describes in Eph 2:4&#8211;5: &#8220;God, who is rich in mercy, made us alive with Christ even when we were dead.&#8221; The bride is prepared before she is sought.</p>",
"16": "<p>&#8220;The woman was very beautiful, a virgin; no man had ever slept with her.&#8221; The purity of the appointed bride is a shadow of the church&#8217;s purity in Christ. 2 Cor 11:2 &#8212; &#8220;I promised you to one husband, to present you as a pure virgin to Christ.&#8221; Eph 5:26&#8211;27 &#8212; &#8220;to make her holy, cleansing her by the washing with water through the word&#8230; to present her to himself as a radiant church, without stain or wrinkle or any other blemish.&#8221; The beauty and virginal purity of Rebekah that the servant recognizes is the type of the church&#8217;s beauty and purity that Christ himself creates in his bride through his own sacrifice. The bride&#8217;s purity is not her own natural condition &#8212; she is cleansed by the bridegroom&#8217;s action.</p>",
"17": "<p>&#8220;Please give me a little water from your jar.&#8221; The servant&#8217;s opening request is modest &#8212; a small ask that creates the space for Rebekah&#8217;s extravagant response. The Spirit&#8217;s gospel work often begins with a small point of contact &#8212; a question, a need, a conversation &#8212; that opens the door to a larger encounter. John 4:7 &#8212; &#8220;Give me a drink&#8221; &#8212; is Jesus&#8217; opening to the Samaritan woman at the well. The well-encounter structure of ch24 is echoed in John 4, where the one who asks for water becomes the one who offers living water. The servant&#8217;s small request creates the opportunity for the bride&#8217;s character to be revealed.</p>",
"18": "<p>&#8220;Drink, my lord&#8221; &#8212; Rebekah&#8217;s immediate, generous response. The word &#8220;quickly&#8221; appears first here (she &#8220;quickly lowered the jar to her hands&#8221;) and will appear again in v20 and v46. The urgency of genuine, unforced generosity &#8212; not grudging compliance but eager service. The spirit of the appointed bride is the spirit of the servant-love that Christ defines as the mark of his disciples (John 13:34&#8211;35 &#8212; &#8220;love one another as I have loved you&#8221;). The response of faith to the Spirit&#8217;s approach is not slow or reluctant &#8212; it is &#8220;drink, my lord&#8221;: open, generous, immediate.</p>",
"19": "<p>&#8220;I&#8217;ll draw water for your camels too, until they have had enough to drink.&#8221; The offer Rebekah makes goes vastly beyond the request. The servant asked for a cup of water; Rebekah offers to water ten camels until they have had enough &#8212; a task requiring many trips to the well and enormous physical effort. This extravagant generosity beyond the minimum required is the character of those formed by Christ&#8217;s love: &#8220;if someone forces you to go one mile, go with them two miles&#8221; (Matt 5:41); &#8220;love your enemies&#8221; (Matt 5:44). The bride&#8217;s character is defined not by what is required but by what love gives freely. The Spirit&#8217;s sign-criterion is met in the extravagance of the response.</p>",
"20": "<p>&#8220;She quickly emptied her jar into the trough, ran back to the well to draw more water.&#8221; The urgency and physicality of Rebekah&#8217;s service &#8212; she &#8220;ran.&#8221; The eagerness of genuine generous service contrasted with the hesitation of Lot (19:16) or the reluctance of Jonah (Jon 1:3). The running reappears in v28 when Rebekah runs home to tell her family. The bride of Christ is characterized by eager responsiveness &#8212; she does not calculate the cost before serving. Gal 5:13 &#8212; &#8220;serve one another humbly in love&#8221; &#8212; describes the community that embodies what Rebekah demonstrates at the well.</p>",
"21": "<p>&#8220;Without saying a word, the man watched her closely to learn whether or not the LORD had made his journey successful.&#8221; The servant&#8217;s silent watchfulness &#8212; not yet speaking, simply observing to discern whether divine guidance is at work. The Spirit&#8217;s work includes discernment: &#8220;The Spirit searches all things, even the deep things of God&#8221; (1 Cor 2:10); &#8220;he will guide you into all the truth&#8221; (John 16:13). The servant does not rush to pronounce; he watches to see whether the Lord has prospered the mission before he acts. This patient discernment &#8212; not forcing the moment but reading what God is doing &#8212; is the pattern of the Spirit&#8217;s wisdom-work in the church.</p>",
"22": "<p>A gold nose ring and two gold bracelets &#8212; the initial gifts given to Rebekah before she knows who her future husband is. The gifts precede the full revelation of the bridegroom; the bride receives them in trust. The Spirit gives gifts to the church before she sees Christ face to face: &#8220;we have been given the Holy Spirit as a deposit, guaranteeing what is to come&#8221; (2 Cor 5:5); the Spirit is &#8220;a deposit guaranteeing our inheritance until the redemption of those who are God&#8217;s possession&#8221; (Eph 1:14). The gold ring and bracelets are the engagement gifts &#8212; the Spirit&#8217;s gifts are the engagement ring, given before the wedding but guaranteeing what the wedding will consummate. 1 Cor 12:4&#8211;11 lists the Spirit&#8217;s gifts distributed to the church now, in the &#8220;betrothal period.&#8221;</p>",
"23": "<p>&#8220;Whose daughter are you?&#8221; &#8212; the servant&#8217;s question about family origin and affiliation. The Spirit&#8217;s work is always to gather those who belong to the covenant family &#8212; to identify and draw those whom the Father is giving to the Son. Rom 8:14&#8211;16 &#8212; &#8220;those who are led by the Spirit of God are the children of God&#8230; the Spirit himself testifies with our spirit that we are God&#8217;s children&#8221; &#8212; is the NT form of the same question: the Spirit identifies whose people they are. The servant&#8217;s question &#8220;whose daughter are you?&#8221; is the Spirit asking: to whom do you belong? Who is your father? The answer determines whether the mission can proceed.</p>",
"24": "<p>&#8220;I am the daughter of Bethuel, the son that Milcah bore to Nahor.&#8221; Rebekah&#8217;s self-identification as within the extended family of Abraham &#8212; Nahor is Abraham&#8217;s brother (11:27). The genealogical connection establishes her eligibility: she is within the covenant family network. The pattern of the gospel gathering the church from within the reach of the covenant promises &#8212; first to those who already stand within the sphere of revelation &#8212; is reflected in Rebekah&#8217;s identity. She is not a Canaanite; she is kin. Rom 1:16 &#8212; &#8220;first to the Jew, then to the Gentile&#8221; &#8212; reflects the same covenant logic of concentric circles of proclamation.</p>",
"25": "<p>&#8220;We have plenty of straw and fodder, as well as room for you to spend the night.&#8221; The welcome extended to the servant &#8212; provision of food, shelter, and rest for both the servant and the camels. The household that welcomes the servant of the master welcomes the master&#8217;s purposes. Luke 10:16 &#8212; &#8220;whoever listens to you listens to me; whoever rejects you rejects me&#8221; &#8212; establishes the principle: the servant&#8217;s reception is the master&#8217;s reception. Rebekah&#8217;s household&#8217;s welcome of the servant is the welcome of Christ&#8217;s mission. The provision of what is needed &#8212; lodging, fodder, space &#8212; is the generous hospitality that opens the door for the proclamation (v33).</p>",
"26": "<p>&#8220;Then the man bowed down and worshiped the LORD.&#8221; The servant&#8217;s immediate response to providential confirmation is not self-congratulation but worship. The servant deflects all attention from himself to the LORD who has guided his mission. The Spirit&#8217;s consistent pattern is to glorify God, not himself: John 16:14 &#8212; &#8220;he will glorify me.&#8221; The doxological response of the servant at v26 is the Spirit&#8217;s response whenever the bride is found: not &#8220;I did this&#8221; but &#8220;blessed be the LORD.&#8221; Worship is the servant&#8217;s language; mission and doxology are inseparable.</p>",
"27": "<p>&#8220;Blessed be the LORD, the God of my master Abraham, who has not abandoned his <em>ḥesed</em> and his faithfulness to my master. As for me, the LORD has led me on the journey to the house of my master&#8217;s relatives.&#8221; The prayer of v12 becomes a doxology of v27 &#8212; the intercession that opened the mission becomes the praise that marks its first success. The twin attributes &#8220;<em>ḥesed</em> and faithfulness&#8221; (<em>ḥesed weʾemet</em>) are the foundational covenant qualities of the LORD (Exod 34:6 &#8212; &#8220;abounding in love and faithfulness&#8221;) and appear throughout the Psalms and prophets as the basis of trust. The servant&#8217;s praise &#8212; &#8220;the LORD has led me&#8221; &#8212; is the testimony of the Spirit&#8217;s guidance in mission: what looked like the servant&#8217;s journey was the LORD&#8217;s leading.</p>",
"28": "<p>&#8220;The young woman ran and told her mother&#8217;s household.&#8221; The second instance of Rebekah &#8220;running&#8221; (cf. v20) &#8212; and this time the running is toward proclamation. The newly encountered person immediately tells her own household. This is the paradigm of witness: Andrew telling Peter (John 1:41 &#8212; &#8220;We have found the Messiah&#8221;), the Samaritan woman leaving her water jar and running to the village (John 4:28 &#8212; &#8220;Come, see a man who told me everything I ever did&#8221;), the healed demoniac sent to tell his own people (Mark 5:19). The first act after meeting the servant of the bridegroom is to tell others. Mission flows from encounter.</p>",
"29": "<p>Laban hurried out to the man at the spring. The older brother&#8217;s response &#8212; &#8220;hurried&#8221; &#8212; mirrors Rebekah&#8217;s urgency. The entire household is in motion. But the narrative will hint at mixed motivations in Laban (v30 &#8212; he sees the gold before he hears the full story). Laban who hurries toward the servant of Abraham is the prototype of his later self in ch29&#8211;31 &#8212; the one who welcomes Jacob because of what he can get. The world often responds to the Spirit&#8217;s mission with apparent eagerness that is driven by material interest rather than genuine covenant welcome. The servant&#8217;s mission will succeed despite Laban&#8217;s mixed motives.</p>",
"30": "<p>Laban sees the nose ring and bracelets on his sister&#8217;s arms, and hears Rebekah&#8217;s words &#8212; then he goes to the man. The text&#8217;s order is significant: the narrative mentions the gold first, then the hearing. Laban&#8217;s welcome of the servant is materially motivated. The gospel is heard and welcomed for mixed reasons &#8212; some for genuine spiritual hunger, some for social benefit, some for material hope. Jesus addresses this in the parable of the sower (Matt 13:3&#8211;9): different soils, different responses, different depths of root. The servant&#8217;s mission succeeds not because all who welcome it welcome it purely, but because God&#8217;s purpose is not thwarted by impure motives in those along the way.</p>",
"31": "<p>&#8220;Come, you who are blessed by the LORD.&#8221; Laban acknowledges the divine blessing on the servant before he even knows the mission. Even those with mixed motives recognize when the Spirit of God is at work &#8212; there is something about the presence of the Spirit that is unmistakable. Acts 5:12&#8211;13 &#8212; &#8220;no one else dared join them, even though they were highly regarded&#8221; &#8212; describes the same phenomenon: the Spirit&#8217;s presence in the church is recognizable even to those who stand at a distance. &#8220;You who are blessed by the LORD&#8221; is an acknowledgment of what Laban can see, even without full understanding.</p>",
"32": "<p>The camels are unloaded, straw and fodder provided, feet washed &#8212; the full hospitality protocol of the Ancient Near East. The washing of feet &#8212; a servant&#8217;s task &#8212; is offered to the servant of Abraham. The hospitality pattern of ch18 (the divine visitors at Mamre) is echoed here: water for feet, food for guests. The receiving of the servant&#8217;s mission with full hospitality &#8212; giving what is needed for the mission to continue &#8212; is the church&#8217;s call (Rom 12:13 &#8212; &#8220;share with the Lord&#8217;s people who are in need. Practice hospitality&#8221;). The house that opens its doors to the servant opens its doors to the master&#8217;s purposes.</p>",
"33": "<p>&#8220;I will not eat until I have told you what I have to say.&#8221; The servant subordinates his own physical need to the urgency of his mission message. Jesus in John 4:34 &#8212; &#8220;My food is to do the will of him who sent me and to finish his work&#8221; &#8212; uses the same structure: the mission is the food, not a meal to be eaten after the mission. The Spirit&#8217;s mission to testify of Christ (John 15:26) is characterized by the same single-mindedness: the Spirit does not prioritize self but the message. The servant&#8217;s refusal to eat until the proclamation is delivered is the defining image of the mission-focused Spirit who counts the proclamation as more essential than physical sustenance.</p>",
"34": "<p>&#8220;I am Abraham&#8217;s servant.&#8221; The servant&#8217;s identity is defined entirely by his relationship to his master. He has no name of his own in the narrative &#8212; he is Abraham&#8217;s servant. The Spirit&#8217;s identity is similarly defined by relationship: &#8220;the Spirit of God&#8221; (Rom 8:9), &#8220;the Spirit of Christ&#8221; (Rom 8:9), &#8220;the Spirit of his Son&#8221; (Gal 4:6). The Spirit&#8217;s self-identification is always relational &#8212; not autonomous but sent and defined by the Father and Son. The opening of the servant&#8217;s proclamation is a declaration of relationship and servitude: everything he says and does proceeds from his identity as the servant of Abraham.</p>",
"35": "<p>&#8220;The LORD has blessed my master abundantly, and he has become wealthy.&#8221; The proclamation begins not with demands but with the master&#8217;s generosity &#8212; with the abundance of blessing that belongs to Abraham. Gospel proclamation in Paul begins the same way: Eph 1:3 &#8212; &#8220;Blessed be the God and Father of our Lord Jesus Christ, who has blessed us in the heavenly realms with every spiritual blessing in Christ.&#8221; Before the invitation comes the declaration of the master&#8217;s abundance. The servant&#8217;s account of Abraham&#8217;s wealth &#8212; sheep, cattle, silver, gold, servants, camels, donkeys &#8212; is the OT equivalent of the NT proclamation of the Father&#8217;s inexhaustible grace.</p>",
"36": "<p>&#8220;My master&#8217;s wife Sarah has borne him a son in her old age, and he has given him everything he owns.&#8221; The center of the proclamation: the son who is heir of all things. Heb 1:2 &#8212; God &#8220;appointed [Christ] heir of all things&#8221; &#8212; is the NT form of &#8220;he has given him everything.&#8221; The gospel proclamation the servant delivers is centered on the son: who the son is (heir of everything the father possesses), what the son has received, and why the bride should want to be joined to him. The Spirit&#8217;s gospel proclamation is always Son-centered: &#8220;he will testify about me&#8221; (John 15:26); &#8220;he will glorify me&#8221; (John 16:14).</p>",
"37": "<p>The servant recounts the oath &#8212; not from the daughters of the Canaanites. The repetition of the instructions (vv37&#8211;41 echo vv3&#8211;8) underscores the servant&#8217;s faithfulness to the master&#8217;s precise instructions. The Spirit speaks only what he hears: John 16:13 &#8212; &#8220;he will not speak on his own; he will speak only what he hears.&#8221; The servant&#8217;s faithful re-narration of Abraham&#8217;s exact words is the pattern of the Spirit&#8217;s proclamation of the Father&#8217;s purposes &#8212; not improvising or adding, but declaring what the master has said. The gospel is not the Spirit&#8217;s own invention; it is the faithful retelling of the Father&#8217;s commission.</p>",
"38": "<p>&#8220;Go to my father&#8217;s family and to my own clan, and get a wife for my son.&#8221; The mission is precise: the bride must come from the covenant family. The church is gathered from among those who have been reached by the gospel &#8212; those who have heard and respond. The precision of the commission &#8212; not just &#8220;find a bride&#8221; but &#8220;from my own clan&#8221; &#8212; reflects the covenant specificity of the Spirit&#8217;s work. The Spirit does not gather randomly but draws those whom the Father has appointed (John 6:37; 17:2). The particularity of the mission is the particularity of election &#8212; not from the whole world indiscriminately but from within the family of the covenant promise.</p>",
"39": "<p>&#8220;What if the woman will not come back with me?&#8221; The servant&#8217;s concern about rejection &#8212; the possibility of refusal &#8212; is voiced again in the re-narration. The Spirit&#8217;s work is not unresisted; the gospel can be refused. 2 Cor 2:15&#8211;16 &#8212; &#8220;to one we are an aroma that brings death; to the other, an aroma that brings life&#8221; &#8212; describes the same reality: the same proclamation produces opposite responses. The servant&#8217;s question anticipates the genuine possibility of refusal, which makes Rebekah&#8217;s &#8220;I will go&#8221; (v58) all the more significant &#8212; the free, chosen &#8220;yes&#8221; of the bride who was under no compulsion.</p>",
"40": "<p>&#8220;The LORD, before whom I have walked faithfully, will send his angel with you and make your journey a success.&#8221; Abraham&#8217;s confidence in divine provision for the servant&#8217;s mission rests on his own track record of walking before God (cf. 17:1 &#8212; &#8220;walk before me faithfully and be blameless&#8221;). The God who has been faithful throughout Abraham&#8217;s life will be faithful in the mission to secure his son&#8217;s bride. This is the confidence of Philippians 1:6 &#8212; &#8220;he who began a good work in you will carry it on to completion until the day of Christ Jesus.&#8221; The Father&#8217;s faithfulness in the past guarantees the Spirit&#8217;s success in the mission of gathering the church.</p>",
"41": "<p>&#8220;If you go to my clan and they refuse to give her to you &#8212; you will be released from my oath.&#8221; The possibility of refusal again &#8212; and the servant&#8217;s release if the bride&#8217;s family refuses. The covenant community can refuse the mission; the servant is not bound to force a result. The history of Israel&#8217;s rejection of the prophets&#8217; message &#8212; and ultimately of Christ himself (John 1:11 &#8212; &#8220;he came to what was his own, but his own did not receive him&#8221;) &#8212; is the fulfillment of the &#8220;if they refuse&#8221; scenario. The servant&#8217;s release from the oath when refused is the type of the Spirit&#8217;s commission being fulfilled in proclamation, not forced in reception.</p>",
"42": "<p>&#8220;When I came to the spring today, I said, &#8216;LORD, God of my master Abraham, if you will, please grant success to the journey on which I have come.&#8217;&#8221; The servant&#8217;s re-narration of the prayer &#8212; offered before the encounter, now retold as testimony to divine guidance. The prayer is the hinge of the servant&#8217;s mission: without it, the encounter at the well is coincidence; with it, it is providence. The Spirit&#8217;s intercessory work undergirds every gospel encounter. Acts 1:14 &#8212; the disciples praying before Pentecost; Acts 4:31 &#8212; the church praying before the Spirit&#8217;s empowerment for bold proclamation. Prayer and mission are inseparable in the servant&#8217;s account.</p>",
"43": "<p>&#8220;See, I am standing beside this spring. If a young woman comes out to draw water.&#8221; The servant&#8217;s re-narration of the sign he requested. The repetition &#8212; the chapter tells the encounter story twice, once in action (vv11&#8211;22) and once in the servant&#8217;s speech (vv42&#8211;48) &#8212; is a literary device that emphasizes the reliability and coherence of the divine guidance. Deut 17:6; Matt 18:16 &#8212; two or three witnesses establish truth. The twice-told story is the narrative equivalent of double witness: the encounter happened precisely as the prayer requested. The Spirit&#8217;s guidance is not vague or ambiguous but specific and verifiable.</p>",
"44": "<p>&#8220;Drink, and I&#8217;ll draw water for your camels too &#8212; let her be the one the LORD has chosen for my master&#8217;s son.&#8221; The re-narration of the sign confirms that Rebekah&#8217;s response was the exact fulfillment of the sign requested. The &#8220;let her be the one the LORD has chosen&#8221; &#8212; <em>yaḥḥtâ hāʾiššâ ʾăšer-hôkîaḥ YHWH</em> &#8212; uses a word translated variously as &#8220;appointed,&#8221; &#8220;designated,&#8221; or &#8220;determined.&#8221; The bride is divinely chosen before the servant meets her. John 15:16 &#8212; &#8220;you did not choose me, but I chose you and appointed you&#8221; &#8212; is the NT form of the same structure: the bride&#8217;s election precedes her response.</p>",
"45": "<p>&#8220;Before I finished praying in my heart, Rebekah came out.&#8221; The emphasis falls on &#8220;in my heart&#8221; &#8212; a silent prayer, not an audible one. Rebekah could not have heard the prayer and staged her response. The divine coordination of a silent prayer with an immediate providential answer is the clearest sign of divine sovereignty in the chapter. God does not need audible prayer to act; he hears the desires of the heart before they are articulated (Ps 139:4 &#8212; &#8220;before a word is on my tongue you, LORD, know it completely&#8221;). The Spirit&#8217;s intercession &#8220;with groans that words cannot express&#8221; (Rom 8:26) operates in the same register &#8212; beyond articulation, directly known by God.</p>",
"46": "<p>&#8220;She quickly lowered her jar from her shoulder and said, &#8216;Drink, and I&#8217;ll water your camels too.&#8217;&#8221; The re-narration of Rebekah&#8217;s extravagant generosity confirms that the sign was exactly met &#8212; not approximately, but precisely. The Spirit&#8217;s work in confirmation is never approximate; when the sign is met, it is met exactly. Acts 2:1&#8211;4 &#8212; the fulfillment of the promise of the Spirit at Pentecost &#8212; is the exact fulfillment of what Joel 2 promised and what Christ promised in John 14&#8211;16. The divine precision of promise and fulfillment is the basis of the servant&#8217;s confidence in his testimony.</p>",
"47": "<p>&#8220;I asked her, &#8216;Whose daughter are you?&#8217;&#8230; Then I put the ring in her nose and the bracelets on her arms.&#8221; The confirmation of Rebekah&#8217;s identity (within the covenant family) leads immediately to the gift of the engagement jewelry &#8212; the gifts follow the confirmed identity. In the Spirit&#8217;s work, the confirmation of identity as God&#8217;s child leads to the reception of gifts: &#8220;Because you are his sons, God sent the Spirit of his Son into our hearts&#8221; (Gal 4:6); &#8220;you received the Spirit of adoption to sonship&#8221; (Rom 8:15). The identity-confirmation and the gift-giving are inseparable &#8212; the Spirit given to those confirmed as children of the Father.</p>",
"48": "<p>&#8220;I bowed down and worshiped the LORD. I praised the LORD, the God of my master Abraham, who had led me on the right road.&#8221; The servant&#8217;s third act of worship in the chapter (cf. vv26&#8211;27 and v52). The mission of finding the bride is punctuated by worship &#8212; at each point of divine confirmation, the servant stops and worships. The Spirit&#8217;s mission produces worship: &#8220;God is spirit, and his worshipers must worship in the Spirit and in truth&#8221; (John 4:24). The servant who has been sent to find a bride for the son keeps redirecting all attention to the LORD. Every step of the mission is received as a gift from God, not an achievement of the servant.</p>",
"49": "<p>&#8220;Tell me; and if not, tell me, so I may know which way to turn.&#8221; The servant requires a decision &#8212; he will not remain in ambiguity. The Spirit&#8217;s proclamation brings people to a point of decision (Acts 2:37 &#8212; &#8220;what shall we do?&#8221;; Acts 17:32 &#8212; some sneered, some wanted to hear more, and some believed). The gospel creates crisis &#8212; not by coercion but by the very nature of the invitation, which requires a response. The servant&#8217;s &#8220;tell me yes or no so I can know which way to turn&#8221; is the invitation to decision that the Spirit always extends through gospel proclamation.</p>",
"50": "<p>&#8220;This is from the LORD; we can say nothing to you one way or the other.&#8221; Laban and Bethuel recognize that the arrangement is divine &#8212; they cannot resist what is clearly from God. The divine initiative in gathering the bride is recognized even by those with mixed motives. John 6:44 &#8212; &#8220;no one can come to me unless the Father who sent me draws them&#8221; &#8212; is the NT form of the same recognition: the gathering of the bride to the Son is from the LORD, not from human arrangement. Even Laban&#8217;s acknowledgment &#8212; however self-interested &#8212; names the theological truth: this is not the servant&#8217;s doing; this is from the LORD.</p>",
"51": "<p>&#8220;Here is Rebekah; take her and go, and let her become the wife of your master&#8217;s son, as the LORD has directed.&#8221; The giving of the bride &#8212; the decisive moment. Rebekah is handed from her father&#8217;s household to the servant, who will bring her to Isaac. John 6:37 &#8212; &#8220;All those the Father gives me will come to me.&#8221; John 17:2 &#8212; &#8220;that he might give eternal life to all those you have given him.&#8221; The Father gives the bride to the Son through the Spirit&#8217;s mission: Bethuel and Laban&#8217;s &#8220;take her&#8221; is the earthly expression of the Father&#8217;s giving of his people to Christ. The one who gives is ultimately the Father; the servant receives and conveys; the Son receives the gift.</p>",
"52": "<p>&#8220;When Abraham&#8217;s servant heard what they said, he bowed down to the ground before the LORD.&#8221; The fourth act of worship in the chapter &#8212; the servant&#8217;s response to the bride&#8217;s being given is immediate prostrate worship. Not triumph, not relief, not self-satisfaction &#8212; worship. The Spirit&#8217;s consistent response to the success of the mission of gathering the bride is to direct all glory to God. Eph 1:14 &#8212; the Spirit is the guarantee of the inheritance &#8220;to the praise of his glory.&#8221; The mission of the Spirit is always doxological in its orientation: the gathering of the bride exists to magnify the Father and the Son, not the Spirit.</p>",
"53": "<p>Gold and silver jewelry, articles of clothing &#8212; the full dowry gifts given to Rebekah, plus costly gifts to her brother and mother. The full generosity of the master&#8217;s resources poured out at the moment of the bride&#8217;s reception. The Spirit&#8217;s gifts to the church are from the Father&#8217;s inexhaustible wealth (1 Cor 12:4&#8211;11 &#8212; gifts distributed as the Spirit determines; Eph 4:7&#8211;8 &#8212; gifts given by the ascended Christ to his church). The giving extends beyond the bride herself to her whole household &#8212; the grace that gathers the bride also blesses those around her. The covenant blessings are not narrowly personal; they overflow.</p>",
"54": "<p>&#8220;Then he and his men ate and drank and spent the night there.&#8221; The covenant meal that follows the betrothal &#8212; eating and drinking together as the seal of the agreement. The Lord&#8217;s Supper is the covenant meal that the betrothed church shares during the &#8220;betrothal period&#8221; between the announcement of the marriage and the wedding feast: &#8220;you proclaim the Lord&#8217;s death until he comes&#8221; (1 Cor 11:26). The eating and drinking of the servant and his household in Laban&#8217;s home is the covenant meal of agreement; the church&#8217;s eating and drinking at the Lord&#8217;s Table is the covenant meal of anticipation.</p>",
"55": "<p>&#8220;Let the young woman remain with us ten days or so; then you may go.&#8221; The family&#8217;s request to delay the departure. The delay between betrothal and wedding &#8212; the &#8220;engagement period&#8221; &#8212; is the type of the church&#8217;s present situation: betrothed to Christ, not yet married; bearing the engagement gifts of the Spirit, not yet in the bridegroom&#8217;s presence. 2 Pet 3:9 &#8212; the delay of Christ&#8217;s return is an expression of divine patience, not divine forgetfulness. The world&#8217;s attempt to delay the bride&#8217;s departure &#8212; to keep her with the old family a little longer &#8212; is the world&#8217;s resistance to the eschatological urgency of the gospel.</p>",
"56": "<p>&#8220;Do not detain me, now that the LORD has granted success to my journey.&#8221; The servant&#8217;s insistence on urgency &#8212; the mission is accomplished; the bride must depart without delay. 2 Cor 6:2 &#8212; &#8220;now is the time of God&#8217;s favor, now is the day of salvation.&#8221; The Spirit&#8217;s eschatological urgency is the urgency of the servant who knows the bridegroom is waiting. The prolonged betrothal is not ideal; the marriage is the goal. The servant&#8217;s refusal to be detained is the refusal of the Spirit to allow the church to become permanently comfortable in the betrothal period &#8212; the goal is the wedding, not the engagement.</p>",
"57": "<p>&#8220;Let&#8217;s call the young woman and ask her about it.&#8221; The bride&#8217;s own will is consulted &#8212; she is not simply handed over without her consent. The gospel requires and honors the bride&#8217;s free response. The Father who gives the bride to the Son gives a bride who freely says &#8220;yes&#8221; &#8212; the divine election and the human free response are not in tension in the narrative. John 6:37 holds both together: &#8220;all those the Father gives me will come to me, and whoever comes to me I will never drive away.&#8221; The &#8220;giving&#8221; and the &#8220;coming&#8221; are both real; the bride is both chosen and free.</p>",
"58": "<p>&#8220;Will you go with this man?&#8221; &#8220;I will go.&#8221; The bride&#8217;s decisive, unqualified response &#8212; the most important words Rebekah speaks in the chapter. She is asked once; she answers immediately. She has not met Isaac; she knows him only through the servant&#8217;s testimony. Her &#8220;I will go&#8221; is faith &#8212; confidence in what she hopes for and assurance about what she has not seen (Heb 11:1). This is the paradigm of the church&#8217;s response to the gospel: going to a bridegroom she has not yet seen, on the testimony of the Spirit alone. 1 Pet 1:8 &#8212; &#8220;though you have not seen him, you love him; and even though you do not see him now, you believe in him.&#8221;</p>",
"59": "<p>&#8220;They sent their sister Rebekah on her way, along with her nurse.&#8221; Deborah, Rebekah&#8217;s nurse (named in 35:8 when she dies at Beth El), accompanies her into the new life. The community that accompanies the bride into the new life &#8212; the church is not a collection of individuals going to Christ in isolation but a community going together. Heb 10:24&#8211;25 &#8212; &#8220;let us consider how we may spur one another on toward love and good deeds, not giving up meeting together.&#8221; The nurse who travels with Rebekah is the type of the covenant community that sustains the bride on the journey toward the bridegroom.</p>",
"60": "<p>&#8220;Our sister, may you increase to thousands upon thousands; may your offspring possess the cities of their enemies.&#8221; The departure blessing mirrors the Abrahamic covenant blessing (22:17 &#8212; &#8220;your descendants will take possession of the cities of their enemies&#8221;). The bride carries the covenant blessing with her as she leaves. Rev 3:21 &#8212; &#8220;to the one who is victorious, I will give the right to sit with me on my throne.&#8221; The bride who goes to the bridegroom shares his inheritance and his victory. The departure blessing spoken over Rebekah is a prophetic declaration of what the church will receive through union with Christ &#8212; co-heir of all things (Rom 8:17).</p>",
"61": "<p>&#8220;Rebekah and her attendants got ready and mounted the camels and went back with the man.&#8221; The departure from the old home on the camels laden with the master&#8217;s gifts &#8212; the bride going toward the bridegroom she has never seen. This is the church&#8217;s posture in the present age: moving toward Christ on the testimony of the Spirit, bearing the gifts of the Spirit, having left the old household behind. Phil 3:13&#8211;14 &#8212; &#8220;forgetting what is behind and straining toward what is ahead, I press on toward the goal to win the prize for which God has called me heavenward in Christ Jesus.&#8221; The journey on the camels is the life of faith moving toward the wedding.</p>",
"62": "<p>&#8220;Now Isaac had come from Beer Lahai Roi, for he was living in the Negev.&#8221; Beer Lahai Roi &#8212; &#8220;the well of the one who sees and lives&#8221; or &#8220;the well of the Living One who sees me&#8221; &#8212; is the place where Hagar encountered the God who sees the outcast (16:14). That Isaac lives near Beer Lahai Roi suggests a connection: the bridegroom dwells near the place where divine grace found the outcast slave. The God who sees Hagar in her distress is the God whose Son makes his dwelling near the marginalized. The geography of the narrative quietly points to a grace that reaches beyond the obvious covenant insiders.</p>",
"63": "<p>&#8220;He went out to the field one evening to meditate.&#8221; Isaac goes out in the evening to meditate (<em>lāśûaḥ</em> &#8212; a hapax legomenon, variously translated &#8220;meditate,&#8221; &#8220;walk,&#8221; &#8220;pray&#8221;) &#8212; and as he looks up, he sees the camels approaching. The bridegroom going out to meet his bride, in the cool of the evening, in a posture of contemplative waiting. This is the posture of the expectant bridegroom: Phil 3:20 &#8212; &#8220;we eagerly await a Savior from there, the Lord Jesus Christ.&#8221; Christ waits for his bride to arrive &#8212; &#8220;he sits at the right hand of God&#8221; (Heb 1:3), interceding and waiting for the consummation. The bridegroom&#8217;s meditation is the prayer of anticipation.</p>",
"64": "<p>&#8220;Rebekah also looked up and saw Isaac.&#8221; The first sight of the bridegroom &#8212; the moment of encounter between the one who has been longing and the one who has been journeying toward him. Rev 22:4 &#8212; &#8220;they will see his face.&#8221; The church has loved Christ without seeing him (1 Pet 1:8); the consummation of that love is the first sight of his face. Rebekah&#8217;s looking up and seeing Isaac is the type of the church&#8217;s final, complete, face-to-face encounter with Christ: &#8220;now I know in part; then I shall know fully, even as I am fully known&#8221; (1 Cor 13:12). The long journey toward the unseen bridegroom ends in sight.</p>",
"65": "<p>&#8220;Who is that man in the field coming to meet us?&#8221; &#8220;He is my master.&#8221; The servant&#8217;s final act is to identify the bridegroom to the bride &#8212; to point to Isaac and name him as &#8220;my master.&#8221; This is the Spirit&#8217;s final mission: to point to Christ and say &#8220;this is the one.&#8221; John 16:14 &#8212; &#8220;he will glorify me, for he will take from what is mine and make it known to you.&#8221; Having brought the bride all the way to the bridegroom, the servant&#8217;s last word is not about himself but about the master. Then Rebekah took her veil and covered herself &#8212; the bride veiling herself before the bridegroom, a gesture of honor and reverence appropriate to the threshold of the wedding. The veiling also carries an eschatological resonance: the church is &#8220;hidden with Christ in God&#8221; (Col 3:3) until the consummation. 1 John 3:2 &#8212; &#8220;what we will be has not yet appeared.&#8221; The bride&#8217;s veil before the wedding is the church&#8217;s present hiddenness before the day she will be presented &#8220;without spot or wrinkle&#8221; (Eph 5:27).</p>",
"66": "<p>&#8220;Then the servant told Isaac all he had done.&#8221; The servant&#8217;s full report to the master &#8212; every detail of the mission, from the prayer at the well to the gifts given to the bride&#8217;s family. The faithful servant renders a complete account of his mission. The Spirit&#8217;s intercession is fully known to the Father: &#8220;he who searches our hearts knows the mind of the Spirit&#8221; (Rom 8:27). The servant&#8217;s report to Isaac is the Spirit&#8217;s intercessory work being fully transparent to the Son &#8212; nothing hidden, nothing omitted, the whole account of how the bride was found and brought. The bridegroom receives the full story of how his bride was gathered.</p>",
"67": "<p>&#8220;Isaac brought her into the tent of his mother Sarah, and he married Rebekah. So she became his wife, and he loved her; and Isaac was comforted after his mother&#8217;s death.&#8221; The wedding &#8212; the fulfillment of the entire chapter&#8217;s mission. The servant&#8217;s oath, the journey, the prayer, the sign, the proclamation, the bride&#8217;s &#8220;I will go&#8221; &#8212; all of it arrives here. The tent of Sarah &#8212; the place where the impossible promise was received (18:9&#8211;10) and where Isaac was born (21:2) &#8212; is the place of the consummation. The covenant that began in impossibility ends in love. &#8220;He loved her&#8221; &#8212; Eph 5:25: &#8220;husbands, love your wives, just as Christ loved the church and gave himself up for her.&#8221; &#8220;Isaac was comforted after his mother&#8217;s death&#8221; &#8212; the joy of the wedding overcomes the grief of loss; John 16:22: &#8220;I will see you again, and you will rejoice, and no one will take away your joy.&#8221; Rev 19:7&#8211;9 &#8212; the marriage supper of the Lamb &#8212; is the NT consummation of what v67 types.</p>"
}
}

def main():
    existing = load_comm('mkt-christ', 'genesis')
    merge_comm(existing, NEW_DATA)
    save_comm('mkt-christ', 'genesis', existing)
    total = len(existing.get('24', {}))
    print(f"  ch24 verses: {total}")
    print("Genesis 24 mkt-christ written.")

if __name__ == '__main__':
    main()
